{"code": "import json
import re

# Load literature & fiction books
books_file = locals()['var_functions.query_db:12']
with open(books_file, 'r') as f:
    lit_fiction_books = json.load(f)

# Filter for English-language books
english_books = []
for book in lit_fiction_books:
    details = book.get('details', '').lower()
    if 'english' in details:
        english_books.append(book)

# Load all reviews
reviews_file = locals()['var_functions.query_db:20']
with open(reviews_file, 'r') as f:
    all_reviews = json.load(f)

# Create mapping from purchase_id to ratings
purchase_ratings = {}
for review in all_reviews:
    purchase_id = review.get('purchase_id', '')
    rating = int(review.get('rating', 0))

    if purchase_id not in purchase_ratings:
        purchase_ratings[purchase_id] = []
    purchase_ratings[purchase_id].append(rating)

# Calculate average ratings
avg_ratings = {}
for purchase_id, ratings in purchase_ratings.items():
    avg_ratings[purchase_id] = sum(ratings) / len(ratings)

# Map book IDs to purchase IDs by extracting numeric part
book_to_purchase = {}
for book in english_books:
    book_id = book.get('book_id', '')
    # Extract numeric part from book_id (e.g., "bookid_1" -> 1)
    match = re.search(r'bookid_(\d+)', book_id)
    if match:
        num = int(match.group(1))
        purchase_id = f'purchaseid_{num}'
        book_to_purchase[book_id] = purchase_id

# Find books with perfect 5.0 average rating
perfect_books = []
for book in english_books:
    book_id = book.get('book_id', '')
    purchase_id = book_to_purchase.get(book_id, '')

    if purchase_id and purchase_id in avg_ratings:
        avg_rating = avg_ratings[purchase_id]
        if avg_rating == 5.0:
            perfect_books.append({
                'book_id': book_id,
                'title': book.get('title', ''),
                'average_rating': avg_rating,
                'total_ratings': len(purchase_ratings[purchase_id])
            })

print('__RESULT__:')
print(json.dumps({
    "english_books_count": len(english_books),
    "books_with_reviews": len(book_to_purchase),
    "perfect_rating_books": perfect_books,
    "sample_purchase_ids": list(purchase_ratings.keys())[:10]
}))"}

